class Solution(object):
    def findThePrefixCommonArray(self, A, B):
        result = []
        seen_a = set()
        seen_b = set()
        count = 0
        for a, b in zip(A, B):
            seen_a.add(a)
            seen_b.add(b)
            if a in seen_b:
                count += 1
            if b in seen_a and a != b:
                count += 1
            result.append(count)
        return result
